parameters.jsCode:
const wh = $('Webhook').item.json.body.payload;
const norm = $('Normalizacao').item.json;
const airtableId = $('Airtable: Create a Record').item.json.id;
const partnerId = $('Resolve or Create Partner').item.json.partner_id;

const qa = wh.questions_and_answers || [];
const idioma = (qa.find(q => /idioma|language/i.test(q.question)) || {}).answer || '';

const start = DateTime.fromISO(wh.scheduled_event.start_time).toUTC();
const dataTriagem = start.toFormat('yyyy-MM-dd HH:mm:ss');
const deadline = start.plus({ days: 10 }).toFormat('yyyy-MM-dd');

const lead = {
  name: `${wh.scheduled_event.name} - ${norm['Nome Completo']}`,
  contact_name: norm['Nome Completo'],
  partner_id: partnerId,            // ← liga ao res.partner criado (id 174)
  email_from: norm.Email,
  phone: norm['Phone Ajustado'],
  mobile: norm['Phone Ajustado'],
  user_id: 6,
  expected_revenue: 100,
  stage_id: 5,
  lead_respostas: idioma ? `Idioma: ${idioma}` : '',
  type: 'opportunity',
  date_deadline: deadline,
  lead_data_triagem: dataTriagem,
  lead_meet_link: wh.scheduled_event.location.join_url,
  lead_calendly_link: 'https://calendly.com/app/scheduled_events/user/me',
  lead_whatsapp: `https://wa.me/${norm['Phone Ajustado']}?text=Ola`,
  lead_airtable_id: airtableId
};

const payload = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      'odoo18',
      2,
      '0fd980f86424e522826d5a2da33e63a5d8a095c1',
      'crm.lead',
      'create',
      [lead]
    ]
  }
};

return [{ json: { odoo_body: JSON.stringify(payload) } }];

