parameters.jsCode:
const ODOO = 'https://odoo.telejud.com/jsonrpc';
const DB = 'odoo18';
const UID = 2;
const KEY = '0fd980f86424e522826d5a2da33e63a5d8a095c1';

const norm = $('Normalizacao').item.json;
const searchResult = $('Search Partner').item.json.result || [];

let partnerId;

if (searchResult.length > 0) {
  // Partner já existe → reusa (pega o primeiro/mais antigo da lista)
  partnerId = searchResult[0].id;
} else {
  // Não existe → cria via jsonrpc usando o helper nativo do n8n (VM2 não tem fetch)
  const createPayload = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [DB, UID, KEY, 'res.partner', 'create', [{
        name: norm['Nome Completo'],
        email: norm.Email,
        phone: norm['Phone Ajustado'],
        mobile: norm['Phone Ajustado']
      }]]
    }
  };

  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: ODOO,
    headers: { 'Content-Type': 'application/json' },
    body: createPayload,
    json: true
  });

  if (data.error) {
    throw new Error('Odoo create partner falhou: ' + JSON.stringify(data.error));
  }
  partnerId = data.result;
}

return [{ json: { partner_id: partnerId } }];

